import React from "react";
import { useParams } from "react-router-dom";
import DnDForm from "./CreateCharacterForms/DnDForm-component";
import PathFinderForm from "./CreateCharacterForms/PathFinderForm-component";
import CallOfCthulhuForm from "./CreateCharacterForms/CallOfCthulhuForm-component";
import VaesenForm from "./CreateCharacterForms/VaesenForm-component";
import CustomForm from "./CreateCharacterForms/CustomForm-component";

const CreateCharacterPage = () => {
  const { system } = useParams();

  const renderForm = () => {
    switch (system) {
      case "dnd":
        return <DnDForm />;
      case "pathfinder":
        return <PathFinderForm />;
      case "call-of-cthulhu":
        return <CallOfCthulhuForm />;
      case "vaesen":
        return <VaesenForm />;
      case "custom":
        return <CustomForm />;
      default:
        return <p>Невідома система</p>;
    }
  };

  return <div className="create-character-page">{renderForm()}</div>;
};

export default CreateCharacterPage;
